import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"限价单与市价单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/limit-and-market.md","filePath":"zh-CN/stock-trading/order-types/limit-and-market.md"}'),i={name:"stock-trading/order-types/limit-and-market.md"};function o(l,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="限价单与市价单" tabindex="-1">限价单与市价单 <a class="header-anchor" href="#限价单与市价单" aria-label="Permalink to &quot;限价单与市价单&quot;">​</a></h1><p>长桥支持多种限价单与市价单变体，适用于港股、美股和集合竞价不同交易时段。</p><h2 id="限价单-limit-order" tabindex="-1">限价单（Limit Order） <a class="header-anchor" href="#限价单-limit-order" aria-label="Permalink to &quot;限价单（Limit Order）&quot;">​</a></h2><p>指定成交价格，只有达到指定价格或更好价格时才执行。买入时可按比限价更低的价格成交，卖出时可按比限价更高的价格成交。</p><table tabindex="0"><thead><tr><th>市场</th><th>可成交时段</th><th>支持有效期</th></tr></thead><tbody><tr><td>港股</td><td>持续交易时段</td><td>当日有效 / 撤销前有效（GTC）/ 特定日期前有效</td></tr><tr><td>美股</td><td>04:00–20:00（美东时间），覆盖盘前、盘中、盘后</td><td>当日有效 / 撤销前有效（GTC）/ 特定日期前有效</td></tr></tbody></table><h2 id="增强限价单-elo" tabindex="-1">增强限价单（ELO） <a class="header-anchor" href="#增强限价单-elo" aria-label="Permalink to &quot;增强限价单（ELO）&quot;">​</a></h2><p>有指定价格的限价盘，仅适用于港股持续交易时段。可同时与最多 10 条轮候队伍配对：卖盘价可较最佳买盘价低 9 个价位，买盘价可较最佳卖盘价高 9 个价位。</p><p>配对后未能成交的部分，转为一般限价盘继续候队。</p><p>支持有效期：当日有效 / 撤销前有效（GTC）/ 特定日期前有效</p><h2 id="竞价限价单-alo" tabindex="-1">竞价限价单（ALO） <a class="header-anchor" href="#竞价限价单-alo" aria-label="Permalink to &quot;竞价限价单（ALO）&quot;">​</a></h2><p>有指定价格的限价盘，适用于港股早盘及收盘集合竞价时段。非集合竞价时段报送时，以预埋单方式暂存，等待下一集合竞价时段报出。对盘后未全部配对的部分，转换为下一时段对应类型订单继续撮合。</p><p>支持有效期：当日有效</p><h2 id="市价单-market-order" tabindex="-1">市价单（Market Order） <a class="header-anchor" href="#市价单-market-order" aria-label="Permalink to &quot;市价单（Market Order）&quot;">​</a></h2><p>不指定价格，只指定数量。成交价格无保证，可能以任何价格成交。</p><table tabindex="0"><thead><tr><th>市场</th><th>可成交时段</th><th>支持有效期</th></tr></thead><tbody><tr><td>港股</td><td>持续交易时段</td><td>当日有效</td></tr><tr><td>美股</td><td>09:30–16:00（美东时间），仅常规时段</td><td>当日有效</td></tr></tbody></table><p><strong>港股市价单</strong>：以当前价格 × 1.2 冻结购买力（乘数可能因市况调整），订单成交或撤销后释放多余购买力。配对后未成交部分系统直接撤单。</p><p><strong>美股市价单</strong>：因盘前盘后流动性有限、波动较大，市价单只在常规时段开盘后发出。</p><h3 id="限价追单机制" tabindex="-1">限价追单机制 <a class="header-anchor" href="#限价追单机制" aria-label="Permalink to &quot;限价追单机制&quot;">​</a></h3><p>市价单以限价形式提交撮合。若因流动性不足未成交，系统自动撤单重新委托；多次重试后仍未成交则取消，可能导致部分成交。市价单提交后不接受手动修改或撤销。适用于港股、美股、美股期权。</p><h3 id="市价单风险提示" tabindex="-1">市价单风险提示 <a class="header-anchor" href="#市价单风险提示" aria-label="Permalink to &quot;市价单风险提示&quot;">​</a></h3><ul><li>高波动市场中可能以不同于预期的价格成交</li><li>低流动性市场中可能以极端价格成交</li><li>不设价格上下限，无法控制具体成交价格</li><li>如需控制价格范围，请使用限价单</li></ul><h3 id="市价单被拒" tabindex="-1">市价单被拒 <a class="header-anchor" href="#市价单被拒" aria-label="Permalink to &quot;市价单被拒&quot;">​</a></h3><p>当股票流动性异常（触发市场波动调节机制、停牌）或波幅过大时，平台可能限制市价单并提示「交易受限制或波动过大」。此时切换至限价单继续下单。</p><h2 id="竞价市价单-ao" tabindex="-1">竞价市价单（AO） <a class="header-anchor" href="#竞价市价单-ao" aria-label="Permalink to &quot;竞价市价单（AO）&quot;">​</a></h2><p>不指定价格的市价盘，适用于港股早盘及收盘集合竞价时段，对盘优先级高于竞价限价单。非集合竞价时段报送以预埋单暂存。对盘后未配对的竞价盘自动取消。</p><p>支持有效期：当日有效</p><h2 id="收盘市价单-market-on-close" tabindex="-1">收盘市价单（Market-On-Close） <a class="header-anchor" href="#收盘市价单-market-on-close" aria-label="Permalink to &quot;收盘市价单（Market-On-Close）&quot;">​</a></h2><p>不指定价格，仅适用于美股。在收盘前 5 分钟下达，以接近收盘价的价格成交。</p><p>可成交时段：09:30–16:00（美东时间）；支持有效期：当日有效</p><h2 id="新加坡柜台特有订单" tabindex="-1">新加坡柜台特有订单 <a class="header-anchor" href="#新加坡柜台特有订单" aria-label="Permalink to &quot;新加坡柜台特有订单&quot;">​</a></h2><p>以下订单类型仅适用于长桥新加坡柜台。</p><h3 id="全部成交或立即取消单-fok" tabindex="-1">全部成交或立即取消单（FOK） <a class="header-anchor" href="#全部成交或立即取消单-fok" aria-label="Permalink to &quot;全部成交或立即取消单（FOK）&quot;">​</a></h3><p>FOK（Fill or Kill）订单必须立即全部执行或完全不执行。若订单不能全部成交，则会被立即取消。</p><p>适用场景：需要确保一次性全部买入/卖出指定数量，不接受部分成交。</p><h3 id="立即成交并取消剩余单-ioc" tabindex="-1">立即成交并取消剩余单（IOC） <a class="header-anchor" href="#立即成交并取消剩余单-ioc" aria-label="Permalink to &quot;立即成交并取消剩余单（IOC）&quot;">​</a></h3><p>IOC（Immediate or Cancel）下单后会尝试立即执行全部或部分订单，未成交的剩余部分会被立即取消。</p><p>适用场景：希望尽快成交，可以接受部分成交，剩余部分不再保留。</p><h3 id="fok-与-ioc-的区别" tabindex="-1">FOK 与 IOC 的区别 <a class="header-anchor" href="#fok-与-ioc-的区别" aria-label="Permalink to &quot;FOK 与 IOC 的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>FOK</th><th>IOC</th></tr></thead><tbody><tr><td>部分成交</td><td>不允许，必须全部成交</td><td>允许部分成交</td></tr><tr><td>未成交处理</td><td>整单取消</td><td>仅取消未成交部分</td></tr></tbody></table><hr><h2 id="通用规则" tabindex="-1">通用规则 <a class="header-anchor" href="#通用规则" aria-label="Permalink to &quot;通用规则&quot;">​</a></h2><h3 id="订单有效期" tabindex="-1">订单有效期 <a class="header-anchor" href="#订单有效期" aria-label="Permalink to &quot;订单有效期&quot;">​</a></h3><table tabindex="0"><thead><tr><th>有效期类型</th><th>说明</th></tr></thead><tbody><tr><td>当日有效</td><td>交易日结束时未成交订单自动取消</td></tr><tr><td>撤销前有效（GTC）</td><td>未完全成交或主动撤销前持续有效。如遇拆股、合并、分红等公司行动，系统在生效日开盘前自动撤销 GTC 订单</td></tr><tr><td>特定日期前有效</td><td>在指定日期前保持有效</td></tr></tbody></table><h3 id="价格上下限" tabindex="-1">价格上下限 <a class="header-anchor" href="#价格上下限" aria-label="Permalink to &quot;价格上下限&quot;">​</a></h3><p>一般情况下，卖出价格不可低于最佳买入价 9 个价位、不可高于最佳卖出价 20 个价位；买入价格不可高于最佳卖出价 9 个价位、不可低于最佳买入价 20 个价位。具体价位随股价而定。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/交易时间与规则/港股交易规则与结算">港股交易规则与结算</a> — ELO 与 ALO 各自适用的具体时段</li><li><a href="/wiki/stock-trading/交易时间与规则/美股交易规则与结算">美股交易规则与结算</a> — 美股限价单与市价单的可用时段</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/order-types/cancel-order">撤销订单</a></li><li><a href="/wiki/stock-trading/order-types">订单类型</a></li></ul>',50)])])}const u=a(i,[["render",o]]);export{b as __pageData,u as default};
